export { VideoContent }

"use client"

import * as React from "react"
import { MessageSquareIcon, RadioIcon } from "lucide-react"
import { CycleIcon } from "@/components/icons/CycleIcon"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { Tabs, TabsList, TabsTrigger, TabsContent } from "@/components/ui/tabs"
import { VideoPlayer } from "@/components/ui/video-player"
import { ChatPanel, type ChatMessage } from "@/components/ui/chat-panel"
import {
  Sheet,
  SheetTrigger,
  SheetContent,
  SheetTitle,
} from "@/components/ui/sheet"
import { CourseContent, type CourseContentFile, type CourseContentProps } from "./course-content"
import { LiveWaiting } from "@/components/ui/live-waiting"
import { cn } from "@/lib/utils"

/* ─── Types ─── */

export type LiveState = "scheduled" | "live" | "ended"

export interface LiveContentProps {
  /** Current state of the live class */
  state: LiveState
  /** HLS stream URL for the live broadcast */
  liveSrc?: string
  /** Recorded video URL (shown in scheduled tab + VOD when ended) */
  recordedSrc?: string
  /** Poster for the recorded video */
  recordedPoster?: string
  /** Activity title */
  title: string
  /** Activity subtitle */
  subtitle?: string
  /** Scheduled start time */
  scheduledAt?: Date
  /** Teacher display name */
  teacherName?: string
  /** Teacher avatar URL */
  teacherAvatar?: string
  /** Live class topic */
  topic?: string
  /** Chat messages */
  messages?: ChatMessage[]
  /** Callback when user sends a chat message */
  onSendMessage?: (message: string) => void
  /** Whether the activity is marked as completed */
  completed?: boolean
  /** Callback to toggle completed state */
  onCompletedChange?: (completed: boolean) => void
  /** Activity description */
  description?: string
  /** Files for download */
  files?: CourseContentFile[]
  /** Files section title */
  filesSectionTitle?: string
  /** Auto-advance callback after completing */
  onAutoAdvance?: CourseContentProps["onAutoAdvance"]
  /** Auto-advance delay (default: 1500ms) */
  autoAdvanceDelay?: CourseContentProps["autoAdvanceDelay"]
  /** Report callback */
  onReport?: CourseContentProps["onReport"]
  /** Label for recorded content tab (default: "Conteúdo") */
  recordedTabLabel?: string
  className?: string
}

/* ─── Hook: detect desktop via pointer ─── */

function useIsDesktop() {
  const [isDesktop, setIsDesktop] = React.useState(false)

  React.useEffect(() => {
    const mq = window.matchMedia("(pointer: fine)")
    setIsDesktop(mq.matches)
    const handler = (e: MediaQueryListEvent) => setIsDesktop(e.matches)
    mq.addEventListener("change", handler)
    return () => mq.removeEventListener("change", handler)
  }, [])

  return isDesktop
}

/* ─── Sub: Live badge indicator ─── */

function LiveBadge() {
  return (
    <Badge variant="destructive" size="sm" className="gap-1 animate-pulse">
      <CycleIcon icon={RadioIcon} size="2xs" decorative />
      AO VIVO
    </Badge>
  )
}

/* ─── Sub: Chat toggle for mobile ─── */

function MobileChatToggle({
  messages,
  onSendMessage,
  disabled,
}: {
  messages: ChatMessage[]
  onSendMessage?: (message: string) => void
  disabled?: boolean
}) {
  return (
    <Sheet>
      <SheetTrigger asChild>
        <Button
          variant="outline"
          size="icon"
          className="fixed bottom-5 right-5 z-30 rounded-full shadow-lg border-border"
          aria-label="Abrir chat"
        >
          <CycleIcon icon={MessageSquareIcon} size="sm" decorative />
          {messages.length > 0 && (
            <span className="absolute -top-1 -right-1 size-4 rounded-full bg-destructive text-[10px] font-bold text-destructive-foreground flex items-center justify-center">
              {messages.length > 99 ? "99+" : messages.length}
            </span>
          )}
        </Button>
      </SheetTrigger>
      <SheetContent side="right" showCloseButton className="w-full sm:max-w-[380px] p-0">
        <SheetTitle className="sr-only">Chat da aula ao vivo</SheetTitle>
        <ChatPanel
          messages={messages}
          onSendMessage={onSendMessage}
          disabled={disabled}
          className="h-full border-l-0"
        />
      </SheetContent>
    </Sheet>
  )
}

/* ─── Sub: Scheduled state (tabs) ─── */

function ScheduledView({
  scheduledAt,
  teacherName,
  teacherAvatar,
  topic,
  recordedSrc,
  recordedPoster,
  recordedTabLabel,
}: {
  scheduledAt?: Date
  teacherName?: string
  teacherAvatar?: string
  topic?: string
  recordedSrc?: string
  recordedPoster?: string
  recordedTabLabel: string
}) {
  const hasRecorded = !!recordedSrc

  if (!hasRecorded) {
    // No recorded content: just show the waiting screen
    return scheduledAt ? (
      <LiveWaiting
        scheduledAt={scheduledAt}
        teacherName={teacherName}
        teacherAvatar={teacherAvatar}
        topic={topic}
      />
    ) : null
  }

  return (
    <Tabs defaultValue="live" className="w-full">
      <TabsList variant="line" className="w-full justify-start px-4 sm:px-0">
        <TabsTrigger value="live" className="gap-1.5">
          <CycleIcon icon={RadioIcon} size="2xs" decorative />
          Ao Vivo
        </TabsTrigger>
        <TabsTrigger value="recorded">{recordedTabLabel}</TabsTrigger>
      </TabsList>

      <TabsContent value="live">
        {scheduledAt ? (
          <LiveWaiting
            scheduledAt={scheduledAt}
            teacherName={teacherName}
            teacherAvatar={teacherAvatar}
            topic={topic}
          />
        ) : (
          <div className="flex items-center justify-center py-16">
            <p className="text-sm text-muted-foreground">
              Aguardando informações da live...
            </p>
          </div>
        )}
      </TabsContent>

      <TabsContent value="recorded">
        <VideoPlayer
          src={recordedSrc}
          poster={recordedPoster}
        />
      </TabsContent>
    </Tabs>
  )
}

/* ─── Sub: Live state ─── */

function LiveView({
  liveSrc,
  messages,
  onSendMessage,
  isDesktop,
}: {
  liveSrc?: string
  messages: ChatMessage[]
  onSendMessage?: (message: string) => void
  isDesktop: boolean
}) {
  return (
    <div className="flex flex-col md:flex-row gap-0">
      {/* Video stream */}
      <div className="flex-1 min-w-0">
        <div className="relative">
          {liveSrc ? (
            <VideoPlayer src={liveSrc} autoPlay muted />
          ) : (
            <div className="aspect-video bg-black flex items-center justify-center rounded-none sm:rounded-[16px]">
              <div className="flex flex-col items-center gap-3">
                <LiveBadge />
                <p className="text-sm text-white/60">
                  Conectando ao stream...
                </p>
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Chat: sidebar on desktop, Sheet on mobile */}
      {isDesktop ? (
        <ChatPanel
          messages={messages}
          onSendMessage={onSendMessage}
          className="w-[340px] shrink-0 h-auto self-stretch"
          title="Chat ao vivo"
        />
      ) : (
        <MobileChatToggle
          messages={messages}
          onSendMessage={onSendMessage}
        />
      )}
    </div>
  )
}

/* ─── Main component ─── */

function LiveContent({
  state,
  liveSrc,
  recordedSrc,
  recordedPoster,
  title,
  subtitle,
  scheduledAt,
  teacherName,
  teacherAvatar,
  topic,
  messages = [],
  onSendMessage,
  completed,
  onCompletedChange,
  description,
  files,
  filesSectionTitle,
  onAutoAdvance,
  autoAdvanceDelay,
  onReport,
  recordedTabLabel = "Conteúdo",
  className,
}: LiveContentProps) {
  const isDesktop = useIsDesktop()

  return (
    <div
      data-slot="live-content"
      data-state={state}
      className={cn("relative mx-auto w-full max-w-[1240px]", className)}
    >
      {/* ─── SCHEDULED ─── */}
      {state === "scheduled" && (
        <div className="flex flex-col gap-6 py-4 sm:py-6 sm:px-10">
          {/* Tabs: Ao Vivo (waiting) | Conteúdo (recorded video) */}
          <ScheduledView
            scheduledAt={scheduledAt}
            teacherName={teacherName}
            teacherAvatar={teacherAvatar}
            topic={topic}
            recordedSrc={recordedSrc}
            recordedPoster={recordedPoster}
            recordedTabLabel={recordedTabLabel}
          />

          {/* Title + description below */}
          <div className="flex flex-col gap-6 px-4 sm:px-0">
            <div className="flex flex-col gap-1">
              <div className="flex items-center gap-2">
                <h1 className="text-xl sm:text-2xl font-semibold tracking-tight text-foreground leading-[30px] sm:leading-8">
                  {title}
                </h1>
                <Badge variant="destructive" size="sm" className="gap-1 shrink-0">
                  <CycleIcon icon={RadioIcon} size="2xs" decorative />
                  Live
                </Badge>
              </div>
              {subtitle && (
                <p className="text-sm sm:text-base text-muted-foreground leading-5 sm:leading-6">
                  {subtitle}
                </p>
              )}
            </div>

            {description && (
              <div className="bg-muted border border-border rounded-2xl px-6 py-6 flex flex-col gap-4">
                <h2 className="text-base sm:text-lg font-semibold tracking-tight text-foreground">
                  Sobre esta aula
                </h2>
                <div className="text-sm sm:text-base text-foreground leading-5 sm:leading-6 whitespace-pre-line">
                  {description}
                </div>
              </div>
            )}
          </div>
        </div>
      )}

      {/* ─── LIVE ─── */}
      {state === "live" && (
        <div className="flex flex-col gap-6 py-4 sm:py-6 sm:px-10">
          <LiveView
            liveSrc={liveSrc}
            messages={messages}
            onSendMessage={onSendMessage}
            isDesktop={isDesktop}
          />

          {/* Title below video */}
          <div className="flex flex-col gap-6 px-4 sm:px-0">
            <div className="flex items-center gap-2">
              <h1 className="text-xl sm:text-2xl font-semibold tracking-tight text-foreground leading-[30px] sm:leading-8">
                {title}
              </h1>
              <LiveBadge />
            </div>
            {subtitle && (
              <p className="text-sm sm:text-base text-muted-foreground leading-5 sm:leading-6 -mt-4">
                {subtitle}
              </p>
            )}
          </div>
        </div>
      )}

      {/* ─── ENDED ─── */}
      {state === "ended" && (
        <CourseContent
          title={title}
          subtitle={subtitle}
          completed={completed}
          onCompletedChange={onCompletedChange}
          description={description}
          files={files}
          filesSectionTitle={filesSectionTitle}
          onAutoAdvance={onAutoAdvance}
          autoAdvanceDelay={autoAdvanceDelay}
          onReport={onReport}
        >
          {recordedSrc ? (
            <VideoPlayer
              src={recordedSrc}
              poster={recordedPoster}
            />
          ) : liveSrc ? (
            <VideoPlayer
              src={liveSrc}
              poster={recordedPoster}
            />
          ) : (
            <div className="aspect-video bg-muted rounded-none sm:rounded-[16px] flex items-center justify-center">
              <p className="text-sm text-muted-foreground">
                A gravação estará disponível em breve.
              </p>
            </div>
          )}
        </CourseContent>
      )}
    </div>
  )
}

export { LiveContent }
